  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import useUniverseCamera from './hooks/useUniverseCamera';
  7→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  8→import MidGalaxyLayer from './layers/MidGalaxyLayer';
  9→import InteractiveLayer from './layers/InteractiveLayer';
 10→import { extractSnippet, userHomeCoords } from './utils/starUtils';
 11→import styles from './Universe.module.css';
 12→
 13→const Universe = () => {
 14→    const navigate = useNavigate();
 15→    const { user } = useAuth();
 16→    const userId = user?.userData?.[0]?.id || null;
 17→
 18→    const debounceRef = useRef(null);
 19→    const [posts, setPosts] = useState(new Map());
 20→    const [selectedPost, setSelectedPost] = useState(null);
 21→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 22→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 23→    const [pulsingId, setPulsingId] = useState(null);
 24→    // null = still loading, true/false = resolved
 25→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 26→
 27→    const {
 28→        stageRef,
 29→        stageSize,
 30→        camera,
 31→        zoom,
 32→        isDragging,
 33→        centerWorld,
 34→        getLayerProps,
 35→        getViewportBounds,
 36→        stageEvents,
 37→    } = useUniverseCamera(userId, hasOwnPosts);
 38→
 39→    // Debounced fetch on camera/zoom change
 40→    useEffect(() => {
 41→        if (debounceRef.current) clearTimeout(debounceRef.current);
 42→
 43→        debounceRef.current = setTimeout(async () => {
 44→            const bounds = getViewportBounds();
 45→            try {
 46→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 47→                if (result?.data) {
 48→                    setPosts(prev => {
 49→                        const next = new Map(prev);
 50→                        for (const post of result.data) {
 51→                            next.set(post.id, post);
 52→                        }
 53→                        return next;
 54→                    });
 55→                    // Check if any returned posts belong to this user
 56→                    if (userId && hasOwnPosts === null) {
 57→                        const ownsAny = result.data.some(p => p.users?.id === userId);
 58→                        setHasOwnPosts(ownsAny);
 59→                    }
 60→                }
 61→            } catch (err) {
 62→                console.error('Failed to fetch universe posts:', err);
 63→            }
 64→        }, 400);
 65→
 66→        return () => {
 67→            if (debounceRef.current) clearTimeout(debounceRef.current);
 68→        };
 69→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 70→
 71→    const handleStarClick = useCallback((post) => {
 72→        setSelectedPost(post);
 73→        setSelectedGalaxy(null);
 74→        setGalaxyProfile(null);
 75→        setPulsingId(post.id);
 76→        setTimeout(() => setPulsingId(null), 400);
 77→    }, []);
 78→
 79→    const handleGalaxyClick = useCallback(async (galaxy) => {
 80→        setSelectedGalaxy(galaxy);
 81→        setSelectedPost(null);
 82→        setGalaxyProfile(null);
 83→        try {
 84→            const data = await getUserData(galaxy.userId);
 85→            const profile = data?.userData?.[0] || null;
 86→            setGalaxyProfile(profile);
 87→        } catch (err) {
 88→            console.error('Failed to fetch galaxy profile:', err);
 89→        }
 90→    }, []);
 91→
 92→    const handleReadPost = useCallback(() => {
 93→        if (!selectedPost) return;
 94→        navigate(`/home/post/${selectedPost.id}`);
 95→    }, [selectedPost, navigate]);
 96→
 97→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 98→    const showTitles = zoom > 0.5;
 99→
100→    // Derive one label per unique user (galaxy)
101→    const galaxies = useMemo(() => {
102→        const seen = new Map();
103→        for (const post of postArray) {
104→            const uid = post.users?.id;
105→            if (!uid || seen.has(uid)) continue;
106→            const home = userHomeCoords(uid);
107→            seen.set(uid, {
108→                userId: uid,
109→                name: post.users?.name || 'Anonymous',
110→                x: home.x,
111→                y: home.y,
112→            });
113→        }
114→        return Array.from(seen.values());
115→    }, [postArray]);
116→
117→    return (
118→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
119→            <button className={styles.backButton} onClick={() => navigate('/home')}>
120→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
121→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
122→                </svg>
123→                Back
124→            </button>
125→
126→            <div className={styles.coordsLabel}>
127→                {centerWorld.x}, {centerWorld.y}
128→            </div>
129→
130→            <Stage
131→                ref={stageRef}
132→                width={stageSize.width}
133→                height={stageSize.height}
134→                {...stageEvents}
135→            >
136→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
137→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
138→                <InteractiveLayer
139→                    layerProps={getLayerProps(1.0)}
140→                    posts={postArray}
141→                    galaxies={galaxies}
142→                    zoom={zoom}
143→                    showTitles={showTitles}
144→                    pulsingId={pulsingId}
145→                    onStarClick={handleStarClick}
146→                    onGalaxyClick={handleGalaxyClick}
147→                />
148→            </Stage>
149→
150→            {selectedGalaxy && galaxyProfile && (
151→                <div className={styles.galaxyPreviewPanel}>
152→                    <button
153→                        className={styles.galaxyPreviewClose}
154→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
155→                    >
156→                        &times;
157→                    </button>
158→                    <div
159→                        className={styles.galaxyPreviewBg}
160→                        style={galaxyProfile.background || {}}
161→                    />
162→                    <div className={styles.galaxyPreviewContent}>
163→                        <img
164→                            className={styles.galaxyPreviewAvatar}
165→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
166→                            alt=""
167→                        />
168→                        <div className={styles.galaxyPreviewHeading}>
169→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
170→                        </div>
171→                        {galaxyProfile.bio && (
172→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
173→                        )}
174→                        <button
175→                            className={styles.galaxyPreviewVisitBtn}
176→                            onClick={() => navigate(`/visit/${selectedGalaxy.userId}`)}
177→                        >
178→                            Visit Profile
179→                        </button>
180→                    </div>
181→                </div>
182→            )}
183→
184→            {selectedPost && (
185→                <div className={styles.previewPanel}>
186→                    <button
187→                        className={styles.previewClose}
188→                        onClick={() => setSelectedPost(null)}
189→                    >
190→                        &times;
191→                    </button>
192→                    <div className={styles.previewAuthor}>
193→                        <img
194→                            className={styles.previewAvatar}
195→                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
196→                            alt=""
197→                        />
198→                        <span className={styles.previewAuthorName}>
199→                            {selectedPost.users?.name || 'Anonymous'}
200→                        </span>
201→                    </div>
202→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
203→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
204→                    <div className={styles.previewLikes}>
205→                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
206→                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
207→                            : '0 likes'}
208→                    </div>
209→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
210→                        Read
211→                    </button>
212→                </div>
213→            )}
214→        </div>
215→    );
216→};
217→
218→export default Universe;
