 1→import React from 'react';
 2→import { Layer, Group, Text } from 'react-konva';
 3→import StarGroup from '../components/StarGroup';
 4→import { getStarColor, getStarRadius } from '../utils/starUtils';
 5→
 6→const GalaxyLabel = React.memo(({ x, y, name, zoom, onClick }) => {
 7→    // Inverse-scale so the label stays a constant screen size
 8→    const invZoom = 1 / zoom;
 9→    return (
10→        <Group x={x} y={y} scaleX={invZoom} scaleY={invZoom}>
11→            <Text
12→                text={name}
13→                fontSize={14}
14→                fill="rgba(255,255,255,0.45)"
15→                fontStyle="600"
16→                fontFamily="inherit"
17→                align="center"
18→                width={200}
19→                offsetX={100}
20→                y={-24}
21→                perfectDrawEnabled={false}
22→                onMouseEnter={(e) => {
23→                    e.target.fill('rgba(255,255,255,0.75)');
24→                    const container = e.target.getStage().container();
25→                    container.style.cursor = 'pointer';
26→                }}
27→                onMouseLeave={(e) => {
28→                    e.target.fill('rgba(255,255,255,0.45)');
29→                    const container = e.target.getStage().container();
30→                    container.style.cursor = 'grab';
31→                }}
32→                onClick={onClick}
33→                onTap={onClick}
34→            />
35→        </Group>
36→    );
37→});
38→
39→GalaxyLabel.displayName = 'GalaxyLabel';
40→
41→const InteractiveLayer = React.memo(({ layerProps, posts, galaxies, zoom, showTitles, pulsingId, onStarClick, onGalaxyClick }) => {
42→    return (
43→        <Layer {...layerProps}>
44→            {/* Galaxy name labels (behind stars) */}
45→            {galaxies?.map((g) => (
46→                <GalaxyLabel
47→                    key={g.userId}
48→                    x={g.x}
49→                    y={g.y}
50→                    name={g.name}
51→                    zoom={zoom}
52→                    onClick={() => onGalaxyClick(g)}
53→                />
54→            ))}
55→            {posts.map((post) => {
56→                const postUserId = post.users?.id;
57→                const color = getStarColor(postUserId);
58→                const likeCount = Array.isArray(post.likes) && post.likes[0]?.count != null
59→                    ? post.likes[0].count
60→                    : 0;
61→                const radius = getStarRadius(likeCount);
62→
63→                return (
64→                    <StarGroup
65→                        key={post.id}
66→                        x={post.universe_x}
67→                        y={post.universe_y}
68→                        radius={radius}
69→                        color={color}
70→                        title={post.title}
71→                        showTitle={showTitles}
72→                        isPulsing={pulsingId === post.id}
73→                        onClick={() => onStarClick(post)}
74→                    />
75→                );
76→            })}
77→        </Layer>
78→    );
79→});
80→
81→InteractiveLayer.displayName = 'InteractiveLayer';
82→
83→export default InteractiveLayer;
