 1→import { STAR_COLORS } from './starUtils';
 2→
 3→// Mulberry32 — fast seeded 32-bit PRNG
 4→const mulberry32 = (seed) => {
 5→    let s = seed | 0;
 6→    return () => {
 7→        s = (s + 0x6D2B79F5) | 0;
 8→        let t = Math.imul(s ^ (s >>> 15), 1 | s);
 9→        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
10→        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
11→    };
12→};
13→
14→const WORLD_SPAN = 100000;
15→const HALF_SPAN = WORLD_SPAN / 2;
16→
17→export const generateDeepSpaceStars = (count = 2000, seed = 42) => {
18→    const rng = mulberry32(seed);
19→    const stars = new Array(count);
20→    for (let i = 0; i < count; i++) {
21→        stars[i] = {
22→            x: rng() * WORLD_SPAN - HALF_SPAN,
23→            y: rng() * WORLD_SPAN - HALF_SPAN,
24→            radius: 0.5 + rng() * 1.5,
25→            opacity: 0.2 + rng() * 0.5,
26→        };
27→    }
28→    return stars;
29→};
30→
31→export const generateMidGalaxyStars = (count = 800, seed = 137) => {
32→    const rng = mulberry32(seed);
33→    const stars = new Array(count);
34→    for (let i = 0; i < count; i++) {
35→        const color = STAR_COLORS[Math.floor(rng() * STAR_COLORS.length)];
36→        stars[i] = {
37→            x: rng() * WORLD_SPAN - HALF_SPAN,
38→            y: rng() * WORLD_SPAN - HALF_SPAN,
39→            radius: 1 + rng() * 3,
40→            opacity: 0.3 + rng() * 0.5,
41→            color,
42→        };
43→    }
44→    return stars;
45→};
46→
47→export const generateNebulae = (count = 18, seed = 256) => {
48→    const rng = mulberry32(seed);
49→    const nebulae = new Array(count);
50→    for (let i = 0; i < count; i++) {
51→        nebulae[i] = {
52→            x: rng() * WORLD_SPAN - HALF_SPAN,
53→            y: rng() * WORLD_SPAN - HALF_SPAN,
54→            radius: 200 + rng() * 600,
55→            opacity: 0.03 + rng() * 0.06,
56→            color: STAR_COLORS[Math.floor(rng() * STAR_COLORS.length)],
57→        };
58→    }
59→    return nebulae;
60→};
61→

 1→export const STAR_COLORS = ['#5f92ff', '#ff5fa2', '#5fffb0', '#ffd75f', '#b05fff', '#ff8a5f'];
 2→
 3→export const HOME_SCALE = 0.8;
 4→export const GUEST_SCALE = 0.05;
 5→
 6→export const simpleHash = (str) => {
 7→    let h = 0;
 8→    for (let i = 0; i < str.length; i++) {
 9→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
10→    }
11→    return Math.abs(h);
12→};
13→
14→export const userHomeCoords = (userId) => {
15→    if (!userId) return { x: 0, y: 0 };
16→    const mid = Math.floor(userId.length / 2);
17→    const xHash = simpleHash(userId.slice(0, mid));
18→    const yHash = simpleHash(userId.slice(mid));
19→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
20→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
21→    return { x, y };
22→};
23→
24→export const getStarColor = (userId) => {
25→    if (!userId) return STAR_COLORS[0];
26→    return STAR_COLORS[simpleHash(userId) % STAR_COLORS.length];
27→};
28→
29→export const getStarRadius = (likeCount) => {
30→    const likes = Math.min(likeCount || 0, 20);
31→    return 6 + likes * 0.3;
32→};
33→
34→export const extractSnippet = (post) => {
35→    if (post.post_type === 'canvas' && post.canvas_doc?.snippets) {
36→        return post.canvas_doc.snippets
37→            .map(s => s?.text || '')
38→            .filter(Boolean)
39→            .join(' ')
40→            .slice(0, 200);
41→    }
42→    if (typeof post.content === 'string') {
43→        try {
44→            const parsed = JSON.parse(post.content);
45→            const extractText = (node) => {
46→                if (!node) return '';
47→                if (typeof node.text === 'string') return node.text;
48→                if (Array.isArray(node.children)) {
49→                    return node.children.map(extractText).join('');
50→                }
51→                return '';
52→            };
53→            return extractText(parsed.root || parsed).slice(0, 200);
54→        } catch {
55→            return post.content.slice(0, 200);
56→        }
57→    }
58→    return '';
59→};
60→
61→export const hexToRgba = (hex, alpha) => {
62→    const r = parseInt(hex.slice(1, 3), 16);
63→    const g = parseInt(hex.slice(3, 5), 16);
64→    const b = parseInt(hex.slice(5, 7), 16);
65→    return `rgba(${r},${g},${b},${alpha})`;
66→};
67→

 1→import React from 'react';
 2→import { Group, Circle, Text } from 'react-konva';
 3→import { hexToRgba } from '../utils/starUtils';
 4→
 5→const StarGroup = React.memo(({ x, y, radius, color, title, showTitle, isPulsing, onClick }) => {
 6→    const r = radius;
 7→
 8→    return (
 9→        <Group
10→            x={x}
11→            y={y}
12→            scaleX={isPulsing ? 1.8 : 1}
13→            scaleY={isPulsing ? 1.8 : 1}
14→        >
15→            {/* Outer atmosphere — shadow glow */}
16→            <Circle
17→                radius={r * 3}
18→                fill="transparent"
19→                shadowColor={color}
20→                shadowBlur={r * 5}
21→                shadowOpacity={1}
22→                perfectDrawEnabled={false}
23→                shadowForStrokeEnabled={false}
24→                listening={false}
25→            />
26→            {/* Inner glow — radial gradient */}
27→            <Circle
28→                radius={r * 2.2}
29→                fillRadialGradientStartPoint={{ x: 0, y: 0 }}
30→                fillRadialGradientEndPoint={{ x: 0, y: 0 }}
31→                fillRadialGradientStartRadius={0}
32→                fillRadialGradientEndRadius={r * 2.2}
33→                fillRadialGradientColorStops={[
34→                    0, color,
35→                    0.4, hexToRgba(color, 0.65),
36→                    1, hexToRgba(color, 0),
37→                ]}
38→                perfectDrawEnabled={false}
39→                listening={false}
40→            />
41→            {/* Bright core */}
42→            <Circle
43→                radius={r * 0.5}
44→                fill="#ffffffee"
45→                shadowColor="#ffffff"
46→                shadowBlur={4}
47→                shadowOpacity={1}
48→                perfectDrawEnabled={false}
49→                hitStrokeWidth={r + 12}
50→                onClick={onClick}
51→                onTap={onClick}
52→            />
53→            {showTitle && title && (
54→                <Text
55→                    text={title.length > 24 ? title.slice(0, 22) + '...' : title}
56→                    y={r * 2.2 + 4}
57→                    fontSize={10}
58→                    fill="rgba(255,255,255,0.6)"
59→                    align="center"
60→                    width={120}
61→                    offsetX={60}
62→                    listening={false}
63→                    perfectDrawEnabled={false}
64→                />
65→            )}
66→        </Group>
67→    );
68→});
69→
70→StarGroup.displayName = 'StarGroup';
71→
72→export default StarGroup;
